import os,re
pats={
'AWS_AKID':re.compile(r'AKIA[0-9A-Z]{16}'),
'AWS_SECRET':re.compile(r'aws_secret_access_key|AWS_SECRET_ACCESS_KEY'),
'AWS_ID':re.compile(r'aws_access_key_id|AWS_ACCESS_KEY_ID'),
'GHP':re.compile(r'gh[pousr]_[0-9A-Za-z]{20,}|github_pat_[0-9A-Za-z_]{20,}'),
'HF':re.compile(r'hf_[0-9A-Za-z]{20,}'),
'GENERIC':re.compile(r'(?i)(secret|token|api[_-]?key|password|passwd|credential)'),
}
for root,dirs,files in os.walk('.'):
    if '/.git' in root or root.endswith('/.git') or '.git' in dirs:
        if '.git' in dirs: dirs.remove('.git')
    for f in files:
        p=os.path.join(root,f)
        try:
            with open(p,encoding='utf-8',errors='ignore') as fh:
                for i,line in enumerate(fh,1):
                    for name,pat in pats.items():
                        if pat.search(line):
                            print(f"{name}\t{p}:{i}\t{line.strip()[:160]}")
        except Exception as e:
            pass
EOF

