import os,re
secrets=[
 re.compile(r'AKIA[0-9A-Z]{16}'),
 re.compile(r'gh[pousr]_[0-9A-Za-z]{20,}'),
 re.compile(r'github_pat_[0-9A-Za-z_]{20,}'),
 re.compile(r'hf_[0-9A-Za-z]{20,}'),
 re.compile(r'AWS_SECRET_ACCESS_KEY=[A-Za-z0-9/+]{20,}'),
 re.compile(r'D4w8z9wKN1aVeT3BpQj6kIuN7wH8X0M9KfV5OqzF'),
]
hits={}
for root,dirs,files in os.walk('.'):
    if '.git' in dirs: dirs.remove('.git')
    for f in files:
        p=os.path.join(root,f)
        try: data=open(p,encoding='utf-8',errors='ignore').read()
        except: continue
        for pat in secrets:
            for m in set(pat.findall(data)):
                hits.setdefault(m,set()).add(p)
for k,v in hits.items():
    print(repr(k), '->', sorted(v))
